=const p = $input.first().json;
const user_id = p.user_id;
const descricao = p.descricao;
const valor = parseFloat(p.valor);
const tipo = p.tipo;
const data_vencimento = p.data_vencimento || new Date().toISOString().split('T')[0];
const categoria_id = p.categoria_id || null;
const forma_pagamento = p.forma_pagamento || 'DINHEIRO';
const status = p.status || 'PENDENTE';

if (!user_id || !descricao || !valor || !tipo) {
  return { response: '⚠️ Erro: Parâmetros obrigatórios ausentes (user_id, descricao, valor, tipo).' };
}
if (!['PAGAR','RECEBER'].includes(tipo)) {
  return { response: '⚠️ Erro: O tipo deve ser PAGAR ou RECEBER.' };
}

try {
  const body = {
    user_id,
    descricao,
    valor,
    tipo,
    data_vencimento,
    status,
    forma_pagamento,
    recorrente: false,
    parcelado: false
  };
  if (categoria_id) body.categoria_id = categoria_id;

  const resp = await fetch(`{{ $vars.SUPABASE_URL }}/rest/v1/transacoes_financeiras`, {
    method: 'POST',
    headers: {
      'apikey': '{{ $vars.SUPABASE_SERVICE_KEY }}',
      'Authorization': `Bearer {{ $vars.SUPABASE_SERVICE_KEY }}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify(body)
  });

  const data = await resp.json();
  if (!resp.ok) return { response: `❌ Erro ao registrar: ${JSON.stringify(data)}` };

  const lancamento = Array.isArray(data) ? data[0] : data;
  const emoji = tipo === 'PAGAR' ? '💸' : '💰';
  const valorFmt = valor.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const dataFmt = new Date(data_vencimento + 'T12:00:00').toLocaleDateString('pt-BR');

  return { response: `${emoji} Lançamento registrado com sucesso!\\n\\n📝 *${descricao}*\\n💵 ${valorFmt}\\n📅 Vencimento: ${dataFmt}\\n🏷️ Tipo: ${tipo === 'PAGAR' ? 'Despesa' : 'Receita'}\\n🔖 Status: ${status}` };
} catch (err) {
  return { response: `⚠️ Erro inesperado: ${err.message}` };
}

=const p = $input.first().json;
const user_id = p.user_id;
const tipo = p.tipo || null;
const limite = parseInt(p.limite) || 10;
const mes = p.mes || null;

if (!user_id) return { response: '⚠️ Erro: user_id é obrigatório.' };

try {
  let qs = `user_id=eq.${user_id}&order=data_vencimento.desc&limit=${limite}&select=id,descricao,valor,tipo,status,data_vencimento,forma_pagamento`;
  if (tipo) qs += `&tipo=eq.${tipo}`;
  if (mes) {
    const [ano, mesNum] = mes.split('-').map(Number);
    const ultimoDia = new Date(ano, mesNum, 0).getDate();
    qs += `&data_vencimento=gte.${mes}-01&data_vencimento=lte.${mes}-${String(ultimoDia).padStart(2,'0')}`;
  }

  const resp = await fetch(`{{ $vars.SUPABASE_URL }}/rest/v1/transacoes_financeiras?${qs}`, {
    headers: {
      'apikey': '{{ $vars.SUPABASE_SERVICE_KEY }}',
      'Authorization': `Bearer {{ $vars.SUPABASE_SERVICE_KEY }}`,
      'Content-Type': 'application/json'
    }
  });

  const data = await resp.json();
  if (!resp.ok) return { response: `❌ Erro ao buscar: ${JSON.stringify(data)}` };
  if (!data || data.length === 0) return { response: '📭 Nenhum lançamento encontrado para os filtros informados.' };

  const totalRec = data.filter(l => l.tipo === 'RECEBER').reduce((s,l) => s + parseFloat(l.valor), 0);
  const totalDesp = data.filter(l => l.tipo === 'PAGAR').reduce((s,l) => s + parseFloat(l.valor), 0);
  const fmt = v => v.toLocaleString('pt-BR', { style:'currency', currency:'BRL' });

  const lista = data.map(l => {
    const e = l.tipo === 'PAGAR' ? '💸' : '💰';
    const s = l.status === 'PAGO' ? '✅' : '⏳';
    const d = new Date(l.data_vencimento + 'T12:00:00').toLocaleDateString('pt-BR');
    return `${e}${s} ${l.descricao}: ${fmt(parseFloat(l.valor))} (${d})`;
  }).join('\\n');

  return { response: `📊 *Lançamentos Encontrados (${data.length}):*\\n\\n${lista}\\n\\n━━━━━━━━━━━━━━━━━━━━━━\\n💰 Receitas: ${fmt(totalRec)}\\n💸 Despesas: ${fmt(totalDesp)}\\n📈 Saldo: ${fmt(totalRec - totalDesp)}` };
} catch (err) {
  return { response: `⚠️ Erro: ${err.message}` };
}

