=const p = $input.first().json;
const user_id = p.user_id;
const titulo = p.titulo;
const descricao = p.descricao || '';
const data_inicio = p.data_inicio;
const tipo = p.tipo || 'PESSOAL';
const status = 'PENDENTE';

if (!user_id || !titulo || !data_inicio) return { response: '⚠️ Erro: Parâmetros obrigatórios (user_id, titulo, data_inicio) ausentes.' };

const tiposValidos = ['REUNIAO_CLIENTE','PRAZO_ENTREGA','PESSOAL','PROFISSIONAL'];
if (!tiposValidos.includes(tipo)) return { response: `⚠️ Erro: Tipo inválido. Use: ${tiposValidos.join(', ')}` };

try {
  const resp = await fetch(`{{ $vars.SUPABASE_URL }}/rest/v1/agendamentos`, {
    method: 'POST',
    headers: {
      'apikey': '{{ $vars.SUPABASE_SERVICE_KEY }}',
      'Authorization': `Bearer {{ $vars.SUPABASE_SERVICE_KEY }}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify({ user_id, titulo, descricao, data_inicio, tipo, status })
  });

  const data = await resp.json();
  if (!resp.ok) return { response: `❌ Erro ao criar agendamento: ${JSON.stringify(data)}` };

  const ag = Array.isArray(data) ? data[0] : data;
  const tipoEmojis = { REUNIAO_CLIENTE:'🤝', PRAZO_ENTREGA:'⏰', PESSOAL:'👤', PROFISSIONAL:'💼' };
  const emoji = tipoEmojis[tipo] || '📅';

  const dataFmt = new Date(data_inicio).toLocaleString('pt-BR', {
    weekday:'long', year:'numeric', month:'long', day:'numeric',
    hour:'2-digit', minute:'2-digit', timeZone:'America/Sao_Paulo'
  });

  return { response: `${emoji} Agendamento criado!\\n\\n📋 *${titulo}*\\n📅 ${dataFmt}${descricao ? `\\n📝 ${descricao}` : ''}\\n🏷️ Tipo: ${tipo.replace('_',' ')}` };
} catch (err) {
  return { response: `⚠️ Erro: ${err.message}` };
}

