=const p = $input.first().json;
const user_id = p.user_id;
const mes = p.mes || new Date().toISOString().substring(0, 7);

if (!user_id) return { response: '⚠️ Erro: user_id é obrigatório.' };

try {
  const [ano, mesNum] = mes.split('-').map(Number);
  const inicio = `${mes}-01`;
  const ultimoDia = new Date(ano, mesNum, 0).getDate();
  const fim = `${mes}-${String(ultimoDia).padStart(2,'0')}`;

  const qs = `user_id=eq.${user_id}&data_vencimento=gte.${inicio}&data_vencimento=lte.${fim}&select=valor,tipo,status`;
  const resp = await fetch(`{{ $vars.SUPABASE_URL }}/rest/v1/transacoes_financeiras?${qs}`, {
    headers: {
      'apikey': '{{ $vars.SUPABASE_SERVICE_KEY }}',
      'Authorization': `Bearer {{ $vars.SUPABASE_SERVICE_KEY }}`,
      'Content-Type': 'application/json'
    }
  });

  const data = await resp.json();
  if (!resp.ok) return { response: `❌ Erro ao buscar resumo: ${JSON.stringify(data)}` };

  const fmt = v => v.toLocaleString('pt-BR', { style:'currency', currency:'BRL' });
  const receitas = data.filter(t => t.tipo === 'RECEBER').reduce((s,t) => s + parseFloat(t.valor), 0);
  const despesas = data.filter(t => t.tipo === 'PAGAR').reduce((s,t) => s + parseFloat(t.valor), 0);
  const recPagas = data.filter(t => t.tipo === 'RECEBER' && t.status === 'PAGO').reduce((s,t) => s + parseFloat(t.valor), 0);
  const despPagas = data.filter(t => t.tipo === 'PAGAR' && t.status === 'PAGO').reduce((s,t) => s + parseFloat(t.valor), 0);
  const saldo = receitas - despesas;
  const saldoReal = recPagas - despPagas;

  const mesNome = new Date(ano, mesNum - 1, 1).toLocaleString('pt-BR', { month:'long', year:'numeric' });
  const saldoEmoji = saldo >= 0 ? '📈' : '📉';
  const saldoRealEmoji = saldoReal >= 0 ? '🟢' : '🔴';

  return { response: `${saldoEmoji} *Resumo — ${mesNome}*\\n\\n💰 Receitas previstas: ${fmt(receitas)}\\n   ↳ realizadas: ${fmt(recPagas)}\\n\\n💸 Despesas previstas: ${fmt(despesas)}\\n   ↳ pagas: ${fmt(despPagas)}\\n\\n${saldoRealEmoji} Saldo realizado: *${fmt(saldoReal)}*\\n📊 Saldo previsto: ${fmt(saldo)}` };
} catch (err) {
  return { response: `⚠️ Erro: ${err.message}` };
}

=const p = $input.first().json;
const user_id = p.user_id;
const titulo = p.titulo;
const descricao = p.descricao || '';
const data_vencimento = p.data_vencimento || null;
const horario_vencimento = p.horario_vencimento || null;
const prioridade = p.prioridade || 'MEDIA';
const tag = p.tag || null;

if (!user_id || !titulo) return { response: '⚠️ Erro: Parâmetros obrigatórios (user_id, titulo) ausentes.' };

const prioridadesValidas = ['ALTA','MEDIA','BAIXA'];
if (!prioridadesValidas.includes(prioridade)) return { response: `⚠️ Erro: Prioridade inválida. Use: ${prioridadesValidas.join(', ')}` };

try {
  const body = { user_id, titulo, descricao, prioridade, concluida: false };
  if (data_vencimento) body.data_vencimento = data_vencimento;
  if (horario_vencimento) body.horario_vencimento = horario_vencimento;
  if (tag) body.tag = tag;

  const resp = await fetch(`{{ $vars.SUPABASE_URL }}/rest/v1/tarefas`, {
    method: 'POST',
    headers: {
      'apikey': '{{ $vars.SUPABASE_SERVICE_KEY }}',
      'Authorization': `Bearer {{ $vars.SUPABASE_SERVICE_KEY }}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify(body)
  });

  const data = await resp.json();
  if (!resp.ok) return { response: `❌ Erro ao criar tarefa: ${JSON.stringify(data)}` };

  const tarefa = Array.isArray(data) ? data[0] : data;
  const prioridadeEmojis = { ALTA:'🔴', MEDIA:'🟡', BAIXA:'🟢' };
  const pEmoji = prioridadeEmojis[prioridade] || '🟡';

  let msg = `✅ Tarefa criada!\\n\\n📌 *${titulo}*\\n${pEmoji} Prioridade: ${prioridade}`;
  if (data_vencimento) {
    const dataFmt = new Date(data_vencimento + 'T12:00:00').toLocaleDateString('pt-BR');
    msg += `\\n📅 Prazo: ${dataFmt}${horario_vencimento ? ' às ' + horario_vencimento : ''}`;
  }
  if (descricao) msg += `\\n📝 ${descricao}`;
  if (tag) msg += `\\n🏷️ Tag: ${tag}`;

  return { response: msg };
} catch (err) {
  return { response: `⚠️ Erro: ${err.message}` };
}
